import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"UXS-004 — Mission Library","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-004.md","filePath":"uxs/UXS-004.md"}'),n={name:"uxs/UXS-004.md"};function s(l,e,r,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="uxs-004-—-mission-library" tabindex="-1">UXS-004 — Mission Library <a class="header-anchor" href="#uxs-004-—-mission-library" aria-label="Permalink to &quot;UXS-004 — Mission Library&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P04_mission-library.html) IA anchor · §surfaces/missions · §topbar-patterns · §shared-tokens Related PRD · PRD-004 Related RFCs · RFC-002 (mission schema), RFC-004 (URL params)</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The mission library is the most HTML-intensive screen — a card grid, filter bar, and detail panel. This UXS defines the card appearance, agency colour system, filter states, and detail panel content layout.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>Agency colour is the dominant identity signal on each card</li><li>The &quot;first&quot; line earns the click — it must be readable at card size</li><li>Filter state is immediately obvious</li><li>The detail panel tells the mission&#39;s story before it lists its data</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, filter bar, card grid, card states, detail panel (OVERVIEW, GALLERY, LEARN tabs), agency logo treatment. Non-goals: card sort order, filter animation. Boundary note: Gallery image loading from NASA API belongs in the screen module.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared tokens, agency colour tokens.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>card-bg:          rgba(8,8,24,0.95)</span></span>
<span class="line"><span>card-border:      rgba(255,255,255,0.06)</span></span>
<span class="line"><span>card-border-hover: rgba(255,255,255,0.15)</span></span>
<span class="line"><span>card-selected:    1px solid [agency-color], box-shadow 0 0 20px [agency-color]22</span></span>
<span class="line"><span>filter-active:    rgba(68,102,255,0.25) bg, rgba(68,102,255,0.5) border</span></span>
<span class="line"><span>filter-inactive:  transparent bg, rgba(255,255,255,0.1) border</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><h3 id="filter-bar-below-nav-40px" tabindex="-1">Filter bar (below nav, 40px) <a class="header-anchor" href="#filter-bar-below-nav-40px" aria-label="Permalink to &quot;Filter bar (below nav, 40px)&quot;">​</a></h3><p>Two filter groups: DESTINATION (ALL / MARS / MOON) and STATUS (ALL / ACTIVE / FLOWN / PLANNED). Each filter is a pill button.</p><h3 id="card-grid" tabindex="-1">Card grid <a class="header-anchor" href="#card-grid" aria-label="Permalink to &quot;Card grid&quot;">​</a></h3><p>Responsive: 3 columns at full width. Each card ~200px wide. Card contains:</p><ul><li>Agency logo top-left (40px)</li><li>Agency colour accent bar left edge (4px)</li><li>Mission name: Bebas Neue 22px</li><li>Type line: Space Mono 7px, <code>rgba(255,255,255,0.4)</code></li><li>Year: Space Mono 8px, <code>rgba(255,255,255,0.3)</code></li><li>&quot;First&quot; line: Space Mono 8px, <code>rgba(255,255,255,0.7)</code></li></ul><h3 id="detail-panel-right-340px" tabindex="-1">Detail panel (right, 340px) <a class="header-anchor" href="#detail-panel-right-340px" aria-label="Permalink to &quot;Detail panel (right, 340px)&quot;">​</a></h3><p>Same panel component as explore screen. Three tabs: OVERVIEW, GALLERY, LEARN.</p><p>OVERVIEW contains:</p><ul><li>Mission header (agency, name, type, status badge)</li><li>Data grid (departure, arrival, transit, vehicle, payload, delta-v)</li><li>Editorial description (Crimson Pro italic 13px)</li><li>&quot;Road to Mars&quot; or &quot;Capability&quot; contextual block (left-border accent)</li><li>FLY THIS MISSION button (if applicable)</li></ul><p>GALLERY: image grid from NASA Images API, 2 columns, captions below each.</p><p>LEARN: tiered links (INTRO teal, CORE blue, DEEP orange).</p><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Card (default):</strong> <code>card-bg</code>, <code>card-border</code>, hover lifts slightly <strong>Card (hovered):</strong> <code>card-border-hover</code>, subtle shadow <strong>Card (selected):</strong> agency-colour border, panel open <strong>Filter pill (active):</strong> <code>filter-active</code><strong>Filter pill (inactive):</strong> <code>filter-inactive</code><strong>Status badge (ACTIVE):</strong> green tint background, &quot;ACTIVE&quot; text <strong>Status badge (FLOWN):</strong> neutral, &quot;FLOWN&quot; <strong>Status badge (PLANNED):</strong> blue tint, &quot;PLANNED&quot; <strong>Data quality badge (partial/reconstructed):</strong> amber, shown in panel header <strong>FLY button (enabled):</strong> same as configurator FLY button <strong>Gallery image (loading):</strong> grey placeholder rect with spinner <strong>Gallery image (loaded):</strong> image with caption below</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Cards: <code>role=&quot;button&quot;</code> or <code>&lt;button&gt;</code>, keyboard navigable, enter to select</li><li>Filter pills: <code>role=&quot;radio&quot;</code> in a <code>role=&quot;radiogroup&quot;</code> per filter group</li><li>Detail panel: semantic headings, screen-reader accessible</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] All 32 mission cards visible, correctly coloured by agency</li><li>[ ] MARS filter shows 16 cards; MOON filter shows 16 cards</li><li>[ ] ACTIVE filter shows only active missions</li><li>[ ] Selected card has agency-colour border</li><li>[ ] Detail panel opens on card click</li><li>[ ] OVERVIEW tab shows all mission data fields</li><li>[ ] GALLERY tab shows NASA Images API results or placeholder</li><li>[ ] LEARN tab shows tiered links in three colour tiers</li><li>[ ] FLY THIS MISSION button present for missions with arc data</li><li>[ ] FLY button navigates to <code>/fly?mission=[id]</code></li></ul><hr><h2 id="extension-—-flight-tab-timeline-navigator-v0-1-7-adr-027" tabindex="-1">Extension — FLIGHT tab + timeline navigator (v0.1.7 / ADR-027) <a class="header-anchor" href="#extension-—-flight-tab-timeline-navigator-v0-1-7-adr-027" aria-label="Permalink to &quot;Extension — FLIGHT tab + timeline navigator (v0.1.7 / ADR-027)&quot;">​</a></h2><p>Two new surfaces on /missions: a per-mission <strong>FLIGHT</strong> tab in the detail panel, and a <strong>timeline navigator</strong> at the top of the screen.</p><h3 id="flight-tab-mission-detail-panel" tabindex="-1">FLIGHT tab (mission detail panel) <a class="header-anchor" href="#flight-tab-mission-detail-panel" aria-label="Permalink to &quot;FLIGHT tab (mission detail panel)&quot;">​</a></h3><p>Sits between OVERVIEW and GALLERY. Two-column layout on desktop (≥768 px), stacked on mobile. Sections:</p><ul><li><strong>Caveat banner</strong> (only when <code>flight_data_quality !== &quot;measured&quot;</code>) — amber, one-line plain-language (&quot;Reconstructed flight data — values approximate&quot;).</li><li><strong>LAUNCH</strong> — vehicle stage, C3 (km²/s²), declination (°), mass at TLI/TMI (kg), source citation.</li><li><strong>CRUISE</strong> — TCM count, peak heliocentric speed (km/s), source.</li><li><strong>ARRIVAL</strong> — V∞ (km/s), entry/orbital geometry (periapsis km / inclination °), orbit-insertion ∆v (km/s), source.</li><li><strong>TOTALS</strong> — total mission ∆v, TLI/TMI ∆v breakdown, source.</li><li><strong>EVENTS</strong> — MET-stamped list, each row: <code>T+nnnd · TYPE · note</code>. Note text comes from i18n overlay; type is enum.</li></ul><p>Each section is collapsible on mobile (initially open). Missing values render as <code>—</code>. Each subsection&#39;s <code>source</code> shows as a small italic citation under the section&#39;s last value.</p><h3 id="timeline-navigator-top-of-missions" tabindex="-1">Timeline navigator (top of /missions) <a class="header-anchor" href="#timeline-navigator-top-of-missions" aria-label="Permalink to &quot;Timeline navigator (top of /missions)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[1957════════════════════════════════════════════════2030]</span></span>
<span class="line"><span>   ·  ·  · · ·    ·   · ·    · · · · ·   · ·· · ·· · ·</span></span>
<span class="line"><span>              ╞══════════════╡   ← drag handles</span></span>
<span class="line"><span>                   [filter: 1969 → 1976]</span></span></code></pre></div><ul><li>Fixed range 1957 → 2030. Decade ticks: <code>1957 1965 1975 1985 1995 2005 2015 2025 2030</code>.</li><li>Mission dots at <code>dot.x = ((mission.year - 1957) / (2030 - 1957)) * width</code>, agency-coloured.</li><li>Two drag handles bound a year-window; cards below filter to the windowed missions.</li><li>Tap/click a dot → jump to that mission (highlights on strip + opens detail panel).</li><li>Pinch-to-zoom on mobile expands the strip into a custom zoom range; two-finger pan slides the window.</li><li>Reduced-motion users see a <code>&lt;input type=&quot;number&quot;&gt;</code> pair for <code>from</code> and <code>to</code> instead of the strip.</li></ul><h3 id="tokens-extension" tabindex="-1">Tokens (extension) <a class="header-anchor" href="#tokens-extension" aria-label="Permalink to &quot;Tokens (extension)&quot;">​</a></h3><p><strong>FLIGHT tab section header:</strong> Bebas Neue, 14 px, <code>rgba(220,230,255,0.95)</code>, letter-spacing 0.08 em <strong>FLIGHT tab value:</strong> Space Mono, 13 px, <code>#fff</code><strong>FLIGHT tab source line:</strong> Crimson Pro italic, 11 px, <code>rgba(180,200,255,0.6)</code><strong>FLIGHT tab caveat banner:</strong> <code>#ffc850</code> border 1 px, <code>rgba(255,200,80,0.18)</code> bg, 12 px Space Mono <strong>Timeline strip height:</strong> 80 px desktop, 64 px mobile <strong>Timeline strip bg:</strong> <code>rgba(20,30,55,0.72)</code> matching panel tint <strong>Timeline tick label:</strong> Space Mono, 10 px, <code>rgba(180,200,255,0.6)</code><strong>Timeline mission dot:</strong> 6 px mobile / 8 px desktop, <code>mission.color</code>, <code>box-shadow 0 0 6px rgba(0,0,0,0.6)</code> for legibility <strong>Timeline drag handle:</strong> 14 px wide, <code>#4ecdc4</code> accent, 44 × 44 hit area per ADR-025 <strong>Timeline windowed range bg:</strong> <code>rgba(78,205,196,0.18)</code></p><h3 id="accessibility-extension" tabindex="-1">Accessibility (extension) <a class="header-anchor" href="#accessibility-extension" aria-label="Permalink to &quot;Accessibility (extension)&quot;">​</a></h3><ul><li>Timeline navigator: <code>role=&quot;slider&quot;</code> per drag handle with <code>aria-valuemin / aria-valuemax / aria-valuenow</code> set in years.</li><li>Mission dots: <code>role=&quot;button&quot;</code> with <code>aria-label=&quot;{mission.name}, launched {year}&quot;</code>.</li><li>Reduced-motion: number inputs labelled &quot;From year&quot; / &quot;To year&quot; with same year bounds.</li><li>FLIGHT tab: each subsection uses <code>&lt;section&gt;</code> with <code>&lt;h3&gt;</code> heading; <code>&lt;dl&gt;</code>/<code>&lt;dt&gt;</code>/<code>&lt;dd&gt;</code> for key-value rows so screen readers traverse coherently.</li></ul><h3 id="acceptance-criteria-extension" tabindex="-1">Acceptance criteria (extension) <a class="header-anchor" href="#acceptance-criteria-extension" aria-label="Permalink to &quot;Acceptance criteria (extension)&quot;">​</a></h3><ul><li>[ ] FLIGHT tab visible only when mission has <code>flight</code> data; falls back gracefully when absent</li><li>[ ] Sparse-data banner shown only when <code>flight_data_quality !== &quot;measured&quot;</code></li><li>[ ] All numeric values render as <code>—</code> when missing — never <code>0</code> or <code>undefined</code></li><li>[ ] Source citations visible per subsection</li><li>[ ] Events list shows MET-stamped entries with i18n notes</li><li>[ ] Timeline navigator strip renders all 32 missions as agency-coloured dots</li><li>[ ] Drag handles filter the card grid below in real time (debounced 100 ms)</li><li>[ ] URL syncs <code>?from=YYYY&amp;to=YYYY</code>; deep-link restores the window</li><li>[ ] Mobile pinch-to-zoom expands the strip; two-finger pan slides</li><li>[ ] Reduced-motion variant: number inputs replace the strip</li><li>[ ] Mission-dot tap highlights + opens detail panel</li><li>[ ] No regression on existing OVERVIEW / GALLERY / LEARN tabs</li></ul>`,49)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
